37	// NewRunner creates a runner with defaults.
38	func NewRunner(cfg Config) *Runner {
39		if cfg.Harness == "" {
40			cfg.Harness = DefaultHarness
41		}
42		if cfg.TimeoutMS == 0 {
43			cfg.TimeoutMS = DefaultTimeoutMS
44		}
45		if cfg.WallClockMS == 0 {
46			cfg.WallClockMS = DefaultWallClockMS
47		}
48		if cfg.SessionLogDir == "" {
49			cfg.SessionLogDir = DefaultLogDir
50		}
51		r := &Runner{
52			registry: newHarnessRegistry(),
53			Config:   cfg,
54			Executor: &OSExecutor{},
55			LookPath: DefaultLookPath,
56		}
57		r.registry.LookPath = func(file string) (string, error) {
58			if r.LookPath != nil {
59				return r.LookPath(file)
60			}
61			return DefaultLookPath(file)
62		}
63		return r
64	}
