66	// Run invokes a single agent harness and returns the result.
67	func (r *Runner) Run(opts RunArgs) (*Result, error) {
68		harness, harnessName, err := r.resolveHarness(opts)
69		if err != nil {
70			return nil, err
71		}
72	
73		// If the provider flag was consumed as a harness name (e.g. "agent",
74		// "local"), clear it so downstream code (RunAgent →
75		// resolveEmbeddedAgentProvider) doesn't try to look it up as a
76		// Fizeau config provider name.
77		if opts.Provider != "" {
78			resolved := resolveHarnessAlias(opts.Provider)
79			if resolved == harnessName {
80				opts.Provider = ""
81			}
82		}
83	
84		// virtual harness: replay from dictionary instead of executing a binary.
85		if harnessName == "virtual" {
86			return runVirtualFn(r, opts)
87		}
88	
89		// Agent harness: run in-process via the embedded agent library.
90		if harnessName == "agent" {
91			return RunAgent(r, opts)
92		}
93	
94		// Script harness: execute directives against the real filesystem and git.
95		if harnessName == "script" {
96			return runScriptFn(r, opts)
97		}
